using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP tools that wrap a weather REST API.
/// The MCP SDK discovers tools via [McpServerToolType] on the class
/// and [McpServerTool] on each method. DI constructor injection works
/// automatically — the host's service provider resolves parameters.
/// </summary>
[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _http;

    // Constructor injection: the DI container provides a typed HttpClient
    // registered via AddHttpClient<WeatherTools>() in Program.cs.
    public WeatherTools(HttpClient http)
    {
        _http = http;
    }

    [McpServerTool, Description("Get current weather for a city")]
    public async Task<string> GetCurrentWeather(
        [Description("City name, e.g. 'Seattle'")] string city,
        CancellationToken cancellationToken = default)
    {
        var response = await _http.GetAsync(
            $"/v1/current.json?q={Uri.EscapeDataString(city)}",
            cancellationToken);

        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        using var doc = JsonDocument.Parse(json);
        var current = doc.RootElement.GetProperty("current");

        return $"Weather in {city}: {current.GetProperty("condition").GetProperty("text")}, " +
               $"{current.GetProperty("temp_c")}°C, " +
               $"Humidity: {current.GetProperty("humidity")}%";
    }

    [McpServerTool, Description("Get a 3-day weather forecast for a city")]
    public async Task<string> GetForecast(
        [Description("City name")] string city,
        [Description("Number of days (1-3)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        var response = await _http.GetAsync(
            $"/v1/forecast.json?q={Uri.EscapeDataString(city)}&days={days}",
            cancellationToken);

        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        using var doc = JsonDocument.Parse(json);
        var forecastDays = doc.RootElement
            .GetProperty("forecast")
            .GetProperty("forecastday")
            .EnumerateArray();

        var lines = forecastDays.Select(day =>
        {
            var dateStr = day.GetProperty("date").GetString();
            var dayData = day.GetProperty("day");
            var condition = dayData.GetProperty("condition").GetProperty("text");
            var maxTemp = dayData.GetProperty("maxtemp_c");
            var minTemp = dayData.GetProperty("mintemp_c");
            return $"  {dateStr}: {condition}, {minTemp}-{maxTemp}°C";
        });

        return $"Forecast for {city}:\n{string.Join("\n", lines)}";
    }
}

using McpServer;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;

var builder = Host.CreateApplicationBuilder(args);

builder.Services
    // Register a typed HttpClient for WeatherTools with a base address.
    // The DI container injects this HttpClient into WeatherTools' constructor.
    .AddHttpClient<WeatherTools>(client =>
    {
        client.BaseAddress = new Uri("https://api.weatherapi.com");
        client.DefaultRequestHeaders.Add("Accept", "application/json");
        // In production, add an API key header or query param here.
    });

builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();

